import {
  buildCotizacionPdfViewerUrl,
  getCotizacionPdfViewerChannelName,
} from "../cotizacion-pdf-viewer";

describe("cotizacion-pdf-viewer utils", () => {
  it("debe construir una ruta limpia para abrir el visor interno del PDF", () => {
    expect(
      buildCotizacionPdfViewerUrl("cot-1", "COT-1232-Alejandro Flores.pdf", "bridge-123")
    ).toBe("/print/cotizaciones/cot-1/archivo/cot-1232-alejandro-flores?bridge=bridge-123");
  });

  it("debe construir un canal estable para el puente del visor", () => {
    expect(getCotizacionPdfViewerChannelName("bridge-123")).toBe(
      "cotizacion-pdf-viewer:bridge-123"
    );
  });
});

